import { Link } from 'react-router-dom';
import styles from './Hero.module.css';

function Hero() {
  return (
    <section className={styles.hero}>
      <div className={styles.content}>
        <p className={styles.kicker}>Easy trip planning</p>
        <h1>Find your next trip without the stress.</h1>
        <p>
          See tour packages, check prices, and plan your travel in one place.
        </p>
        <Link to="/packages" className={styles.ctaButton}>
          Explore Destinations
        </Link>
      </div>
      <div className={styles.visualCard}>
        <div>
          <span>Popular trips</span>
          <strong>Beach, mountain, heritage, and international tours</strong>
        </div>
      </div>
    </section>
  );
}

export default Hero;
